class SecureWebViewController: UIViewController {
    
    private var webView: WKWebView!
    private let allowedOrigins = ["https://yourdomain.com", "https://www.yourdomain.com"]
    private let messageHandlerName = "nativeHandler"
    
    private struct WebMessage: Codable {
        let action: String
        let requestId: String
        let parameters: [String: String]?
    }
    
    private enum NativeAction: String {
        case requestCamera
        case requestNotifications
        case initiatePurchase
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        loadSecureContent()
    }
    
    private func setupWebView() {
        let configuration = WKWebViewConfiguration()
        
        configuration.preferences.javaScriptEnabled = true
        configuration.preferences.javaScriptCanOpenWindowsAutomatically = false
        
        if #available(iOS 14.0, *) {
            configuration.defaultWebpagePreferences.allowsContentJavaScript = true
        }
        
        configuration.allowsInlineMediaPlayback = true
        configuration.mediaTypesRequiringUserActionForPlayback = .all
        configuration.allowsAirPlayForMediaPlayback = false
        configuration.allowsPictureInPictureMediaPlayback = false
        
        let contentController = WKUserContentController()
        contentController.add(self, name: messageHandlerName)
        configuration.userContentController = contentController
        
        webView = WKWebView(frame: .zero, configuration: configuration)
        webView.navigationDelegate = self
        webView.uiDelegate = self
        webView.translatesAutoresizingMaskIntoConstraints = false
        webView.allowsBackForwardNavigationGestures = true
        
        view.addSubview(webView)
        
        NSLayoutConstraint.activate([
            webView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            webView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            webView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            webView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    private func loadSecureContent() {
        guard let url = URL(string: allowedOrigins[0]) else { return }
        let request = URLRequest(url: url, cachePolicy: .reloadIgnoringLocalCacheData, timeoutInterval: 30)
        webView.load(request)
    }
    
    private func isOriginAllowed(_ url: URL?) -> Bool {
        guard let url = url,
              let scheme = url.scheme,
              scheme == "https",
              let host = url.host else {
            return false
        }
        
        return allowedOrigins.contains { allowedOrigin in
            guard let allowedURL = URL(string: allowedOrigin),
                  let allowedHost = allowedURL.host else {
                return false
            }
            return host == allowedHost
        }
    }
    
    private func validateAndParseMessage(_ body: Any) -> WebMessage? {
        guard let messageDict = body as? [String: Any],
              let action = messageDict["action"] as? String,
              let requestId = messageDict["requestId"] as? String,
              !requestId.isEmpty,
              requestId.count < 100 else {
            return nil
        }
        
        let parameters = messageDict["parameters"] as? [String: String]
        
        return WebMessage(action: action, requestId: requestId, parameters: parameters)
    }
    
    private func sendResponse(requestId: String, success: Bool, data: [String: Any]? = nil, error: String? = nil) {
        var response: [String: Any] = [
            "requestId": requestId,
            "success": success
        ]
        
        if let data = data {
            response["data"] = data
        }
        
        if let error = error {
            response["error"] = error
        }
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: response, options: []),
              let jsonString = String(data: jsonData, encoding: .utf8) else {
            return
        }
        
        let script = "window.nativeResponse(\(jsonString));"
        webView.evaluateJavaScript(script, completionHandler: nil)
    }
    
    private func handleCameraRequest(requestId: String, parameters: [String: String]?) {
        let authStatus = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch authStatus {
        case .authorized:
            sendResponse(requestId: requestId, success: true, data: ["status": "authorized"])
            
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    self?.sendResponse(requestId: requestId, success: granted, data: ["status": granted ? "authorized" : "denied"])
                }
            }
            
        case .denied, .restricted:
            sendResponse(requestId: requestId, success: false, error: "Camera access denied")
            
        @unknown default:
            sendResponse(requestId: requestId, success: false, error: "Unknown authorization status")
        }
    }
    
    private func handleNotificationRequest(requestId: String, parameters: [String: String]?) {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            DispatchQueue.main.async {
                switch settings.authorizationStatus {
                case .authorized, .provisional:
                    self?.sendResponse(requestId: requestId, success: true, data: ["status": "authorized"])
                    
                case .notDetermined:
                    UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) { granted, error in
                        DispatchQueue.main.async {
                            if let error = error {
                                self?.sendResponse(requestId: requestId, success: false, error: error.localizedDescription)
                            } else {
                                self?.sendResponse(requestId: requestId, success: granted, data: ["status": granted ? "authorized" : "denied"])
                                if granted {
                                    UIApplication.shared.registerForRemoteNotifications()
                                }
                            }
                        }
                    }
                    
                case .denied:
                    self?.sendResponse(requestId: requestId, success: false, error: "Notification access denied")
                    
                @unknown default:
                    self?.sendResponse(requestId: requestId, success: false, error: "Unknown authorization status")
                }
            }
        }
    }
    
    private func handlePurchaseRequest(requestId: String, parameters: [String: String]?) {
        guard let productId = parameters?["productId"],
              !productId.isEmpty,
              productId.range(of: "^[a-zA-Z0-9._-]+$", options: .regularExpression) != nil else {
            sendResponse(requestId: requestId, success: false, error: "Invalid product ID")
            return
        }
        
        if SKPaymentQueue.canMakePayments() {
            let productIdentifiers: Set<String> = [productId]
            let request = SKProductsRequest(productIdentifiers: productIdentifiers)
            
            let delegate = ProductRequestDelegate(requestId: requestId, viewController: self)
            request.delegate = delegate
            request.start()
            
            objc_setAssociatedObject(self, "productDelegate_\(requestId)", delegate, .OBJC_ASSOCIATION_RETAIN)
        } else {
            sendResponse(requestId: requestId, success: false, error: "In-app purchases are disabled")
        }
    }
    
    deinit {
        webView.configuration.userContentController.removeScriptMessageHandler(forName: messageHandlerName)
    }
}

extension SecureWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard message.name == messageHandlerName,
              isOriginAllowed(webView.url),
              let webMessage = validateAndParseMessage(message.body) else {
            return
        }
        
        guard let action = NativeAction(rawValue: webMessage.action) else {
            sendResponse(requestId: webMessage.requestId, success: false, error: "Unknown action")
            return
        }
        
        switch action {
        case .requestCamera:
            handleCameraRequest(requestId: webMessage.requestId, parameters: webMessage.parameters)
            
        case .requestNotifications:
            handleNotificationRequest(requestId: webMessage.requestId, parameters: webMessage.parameters)
            
        case .initiatePurchase:
            handlePurchaseRequest(requestId: webMessage.requestId, parameters: webMessage.parameters)
        }
    }
}

extension SecureWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        if isOriginAllowed(url) {
            decisionHandler(.allow)
        } else {
            if UIApplication.shared.canOpenURL(url) {
                UIApplication.shared.open(url, options: [:], completionHandler: nil)
            }
            decisionHandler(.cancel)
        }
    }
    
    func webView(_ webView: WKWebView, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust,
              isOriginAllowed(URL(string: challenge.protectionSpace.host)) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        print("Navigation failed: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        print("Provisional navigation failed: \(error.localizedDescription)")
    }
}

extension SecureWebViewController: WKUIDelegate {
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        guard isOriginAllowed(frame.request.url) else {
            completionHandler()
            return
        }
        
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        guard isOriginAllowed(frame.request.url) else {
            completionHandler(false)
            return
        }
        
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

private class ProductRequestDelegate: NSObject, SKProductsRequestDelegate {
    let requestId: String
    weak var viewController: SecureWebViewController?
    
    init(requestId: String, viewController: SecureWebViewController) {
        self.requestId = requestId
        self.viewController = viewController
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            
            if let product = response.products.first {
                let payment = SKPayment(product: product)
                SKPaymentQueue.default().add(payment)
                
                self.viewController?.sendResponse(
                    requestId: self.requestId,
                    success: true,
                    data: [
                        "productId": product.productIdentifier,
                        "status": "initiated"
                    ]
                )
            } else {
                self.viewController?.sendResponse(
                    requestId: self.requestId,
                    success: false,
                    error: "Product not found"
                )
            }
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            self.viewController?.sendResponse(
                requestId: self.requestId,
                success: false,
                error: error.localizedDescription
            )
        }
    }
}